// Extrair dados do payload da Evolution API
const input = $input.first().json;
let body = input.body || input;

if (typeof body === 'string') {
  try {
    body = JSON.parse(body);
  } catch (error) {
    body = {};
  }
}

const data = body.data || {};
const key = data.key || {};
const msg = data.message || {};
const instance = body.instance || data.instance || '';
const modoPessoal = instance === 'fabioos-pessoal';

const texto = msg.conversation
  || msg.extendedTextMessage?.text
  || '';
const textoLimpo = texto.trim();

const jid = key.remoteJid || '';
const isGroup = jid.endsWith('@g.us');
const numeroCompleto = jid.replace('@s.whatsapp.net', '').replace('@g.us', '');
const numeroAnon = '****' + numeroCompleto.slice(-4);

const nome = data.pushName || (modoPessoal ? 'Fabio' : 'Responsavel');
const timestamp = data.messageTimestamp || Math.floor(Date.now() / 1000);
const dataHora = new Date(timestamp * 1000).toISOString().replace('T', ' ').substring(0, 16);
const hoje = new Date(timestamp * 1000).toISOString().split('T')[0];
const anoMes = hoje.substring(0, 7);

if (isGroup) {
  return [{ json: { ignorar: true, motivo: 'grupo_nao_suportado' } }];
}

if (key.fromMe && !modoPessoal) {
  return [{ json: { ignorar: true, motivo: 'mensagem_enviada_pelo_numero' } }];
}

if (!textoLimpo) {
  return [{ json: { ignorar: true, motivo: 'sem_texto' } }];
}

const messageId = `wa-${timestamp}-${numeroCompleto.slice(-4)}-${Math.random().toString(36).slice(2, 7)}`;

return [{
  json: {
    texto: textoLimpo,
    numeroAnon,
    numeroCompleto,
    fromMe: !!key.fromMe,
    nome,
    instance,
    modo: modoPessoal ? 'pessoal' : 'escola',
    dataHora,
    hoje,
    anoMes,
    messageId,
    logFilename: modoPessoal ? `WHATSAPP_PESSOAL_${anoMes}_LOG.md` : `PIETRA_${anoMes}_LOG.md`,
    ignorar: false
  }
}];

// Classificar intent da mensagem com base nas palavras-gatilho do Pietra
const texto = $json.texto.toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '');

const categorias = [
  { nome: 'ocorrencia', nivel: 'alto', escalonar: true, gatilhos: ['ocorrencia', 'suspensao', 'briga', 'conflito', 'bullying', 'agressao', 'ameaca', 'assedio', 'disciplinar', 'expulsao'], resposta_key: 'OCORRENCIA_ESCALONAMENTO' },
  { nome: 'financeiro', nivel: 'alto', escalonar: false, gatilhos: ['mensalidade', 'boleto', 'pagamento', 'atraso', 'debito', 'vencimento', 'inadimplente', 'bolsa'], resposta_key: 'FINANCEIRO_REDIRECIONAMENTO' },
  { nome: 'matricula', nivel: 'medio', escalonar: false, gatilhos: ['matricula', 'rematricula', 'inscricao', 'vaga', 'novo aluno'], resposta_key: 'MATRICULA_INFO' },
  { nome: 'segunda_chamada', nivel: 'medio', escalonar: false, gatilhos: ['segunda chamada', 'faltou na prova', 'atestado', 'justificativa de falta'], resposta_key: 'SEGUNDA_CHAMADA_PROCEDIMENTO' },
  { nome: 'prova', nivel: 'medio', escalonar: false, gatilhos: ['prova', 'avaliacao', 'simulado', 'recuperacao', 'nota', 'gabarito'], resposta_key: 'PROVA_DATA_CONTEUDO' },
  { nome: 'coordenacao', nivel: 'medio', escalonar: false, gatilhos: ['coordenacao', 'coordenador', 'reuniao', 'reclamacao'], resposta_key: 'COORDENACAO_AGENDAMENTO' },
  { nome: 'secretaria', nivel: 'medio', escalonar: false, gatilhos: ['declaracao', 'historico', 'documento', 'transferencia'], resposta_key: 'SECRETARIA_DOCUMENTOS' },
  { nome: 'duvida_pedagogica', nivel: 'medio', escalonar: false, gatilhos: ['dificuldade', 'reforco', 'laudo', 'necessidade especial'], resposta_key: 'PEDAGOGICO_REDIRECIONAMENTO' },
  { nome: 'professor', nivel: 'baixo', escalonar: false, gatilhos: ['professor', 'prof ', 'contato do professor'], resposta_key: 'PROFESSOR_CONTATO' },
  { nome: 'material', nivel: 'baixo', escalonar: false, gatilhos: ['lista de material', 'livro', 'apostila', 'uniforme'], resposta_key: 'MATERIAL_LISTA' },
  { nome: 'horario', nivel: 'baixo', escalonar: false, gatilhos: ['horario', 'feriado', 'recesso'], resposta_key: 'HORARIO_INFO' }
];

let melhorCategoria = null;
let melhorPontuacao = 0;
for (const cat of categorias) {
  let pontos = 0;
  for (const gatilho of cat.gatilhos) {
    if (texto.includes(gatilho)) pontos++;
  }
  if (pontos > melhorPontuacao) {
    melhorPontuacao = pontos;
    melhorCategoria = cat;
  }
}
if (!melhorCategoria || melhorPontuacao === 0) {
  melhorCategoria = { nome: 'nao_classificada', nivel: 'medio', escalonar: false, resposta_key: 'NAO_CLASSIFICADO' };
}
const palavrasRisco = ['advogado', 'procon', 'processo', 'abuso', 'violencia'];
const temRisco = palavrasRisco.some(p => texto.includes(p));
if (temRisco) melhorCategoria.escalonar = true;

const extrair = $('Extrair Dados').item.json;
return [{
  json: {
    ...extrair,
    agentariumJobId: $('Pietra -> Agentarium').item.json.jobId,
    categoria: melhorCategoria.nome,
    nivel: melhorCategoria.nivel,
    escalonar: melhorCategoria.escalonar || temRisco,
    resposta_key: melhorCategoria.resposta_key,
    pontuacao: melhorPontuacao
  }
}];

const d = $json;
const acao = d.escalonar ? 'escalada' : 'sugestao_preparada';
const logLinha = `| ${d.dataHora} | WhatsApp | ${d.numeroAnon} | ${d.categoria} | ${d.nivel} | ${acao} | pendente |\n`;
const notificacao = [
  `[PIETRA] Nova mensagem recebida`,
  `Canal: WhatsApp | Numero: ${d.numeroAnon}`,
  `Categoria: ${d.categoria} | Nivel: ${d.nivel}`,
  d.escalonar ? 'ESCALONAMENTO OBRIGATORIO' : '',
  ``,
  `Mensagem: "${d.texto}"`,
  ``,
  d.agentariumJobId ? `Agentarium job: ${d.agentariumJobId}` : ''
].filter(Boolean).join('\n');
return [{ json: { ...d, logLinha, notificacao, acao } }];
